patch:
diff --git a/llvm/lib/Transforms/Scalar/GVNSink.cpp b/llvm/lib/Transforms/Scalar/GVNSink.cpp
index 2058df33ea33..c99126ef60e1 100644
--- a/llvm/lib/Transforms/Scalar/GVNSink.cpp
+++ b/llvm/lib/Transforms/Scalar/GVNSink.cpp
@@ -679,6 +679,12 @@ GVNSink::analyzeInstructionForSinking(LockstepReverseIterator<false> &LRI,
   // try and continue making progress.
   Instruction *I0 = NewInsts[0];

+  for (auto *I : NewInsts) { 
+    if (isa<CallInst>(I) && cast<CallInst>(I)->isInlineAsm()) { 
+      LLVM_DEBUG(dbgs() << "Skipping inline asm instruction: " << *I << "\n"); 
+      return std::nullopt; 
+    } 
+  }
   auto isNotSameOperation = [&I0](Instruction *I) {
     return !I0->isSameOperationAs(I);
   };

